import json

class PatientRecord:
    def __init__(self, record_id):
        self.record_id = record_id
        self.data = {}

    def update_data(self, key, value):
        self.data[key] = value
        self._write_to_disk()

    def _write_to_disk(self):
        with open(f"{self.record_id}.json", "w") as file:
            json.dump(self.data, file)

